/* -------  GENDER PAGE TINT ------- */

html[data-wtm-gender="men"] {
  --wtm-page-bg: #e8f0ff;
}

html[data-wtm-gender="women"] {
  --wtm-page-bg: #fff0f7;
}

html[data-wtm-gender="unisex"] {
  --wtm-page-bg: #f4edff;
}

/* Broad page background areas */
html[data-wtm-gender] body,
html[data-wtm-gender] main,
html[data-wtm-gender] section,
html[data-wtm-gender] article,
html[data-wtm-gender] fieldset,
html[data-wtm-gender] [data-test*="-section"],
html[data-wtm-gender] [data-test*="-container"] {
  background-color: var(--wtm-page-bg) !important;
}

