/* Size-name column */
[data-test="measurements-table-left-table-sticky-columns"],
[data-test="measurements-table-left-table-sticky-columns"] th,
[data-test="measurements-table-left-table-sticky-columns"] td {
    width: 80px !important;
    min-width: 80px !important;
}

/* Measurement columns */
table[data-test="undefined-scrollable-columns"] th,
table[data-test="undefined-scrollable-columns"] td {
    width: 120px !important;
    min-width: 120px !important;
    max-width: 120px !important;
}

table[data-test="undefined-scrollable-columns"] input[type="number"] {
    width: 100% !important;
    box-sizing: border-box !important;
}

/* Hide - "Does not vary by size"
table[data-test="undefined-scrollable-columns"]
label input[type="checkbox"] ~ p {
    display: none !important;
}
*/

/* Replace “Does not vary by size” visually with “Fixed Size” */
table[data-test="undefined-scrollable-columns"]
label input[type="checkbox"] ~ p {
    font-size: 0 !important;
}

table[data-test="undefined-scrollable-columns"]
label input[type="checkbox"] ~ p::after {
    content: "Fixed Size";
    font-size: 10px !important;
    line-height: 1.2 !important;
    white-space: nowrap !important;
}

/* Reduce checkbox/text spacing */
table[data-test="undefined-scrollable-columns"] thead label {
    gap: 4px !important;
}





/* 
Title on first line, checkbox on second line 
*/

table[data-test="undefined-scrollable-columns"] thead th > div {
    display: flex !important;
    flex-direction: column !important;
    align-items: flex-start !important;
    justify-content: flex-start !important;
    height: 100% !important;
}

table[data-test="undefined-scrollable-columns"] thead label {
    display: flex !important;
    align-items: center !important;
    white-space: nowrap !important;
    margin-top: 6px !important;
}

/* Equal header height in both tables */
table[data-test="undefined-scrollable-columns"] thead th,
table[data-test="measurements-table-left-table-sticky-columns"] thead th {
    height: 85px !important;
    min-height: 85px !important;
    box-sizing: border-box !important;
    vertical-align: top !important;
}
